const fs = require\('fs'\);
const path = require\('path'\);

function collectFiles\(dir, exts\) {
  const results = [];
  if \(!fs.existsSync\(dir\)\) return results;
  for \(const e of fs.readdirSync\(dir, { withFileTypes: true }\)\) {
    const full = path.join\(dir, e.name\);
    if \(e.isDirectory\(\)\) results.push\(...collectFiles\(full, exts\)\);
    else if \(exts.some\(x => e.name.endsWith\(x\)\)\) results.push\(full\);
  }
  return results;
}

const files = [
  ...collectFiles\('app', ['.tsx']\),
  ...collectFiles\('src/components', ['.tsx']\),
];

let totalFixed = 0;
let filesFixed = 0;

for \(const f of files\) {
  const orig = fs.readFileSync\(f, 'utf-8'\);
  // Replace fontSize: 8, 9, 10 → 11 \(only exact values, not 18, 28, etc.\)
  let fixed = orig
    .replace\(/\\bfontSize\\s*:\\s*8\\b/g, 'fontSize: 11'\)
    .replace\(/\\bfontSize\\s*:\\s*9\\b/g, 'fontSize: 11'\)
    .replace\(/\\bfontSize\\s*:\\s*10\\b/g, 'fontSize: 11'\);

  if \(fixed !== orig\) {
    const count = \(orig.match\(/\\bfontSize\\s*:\\s*\(?:8|9|10\)\\b/g\) || []\).length;
    totalFixed += count;
    filesFixed++;
    fs.writeFileSync\(f, fixed, 'utf-8'\);
    console.log\('  Fixed ' + count + ' occurrence\(s\) in ' + f.replace\(process.cwd\(\) + '/', ''\)\);
  }
}

console.log\(''\);
console.log\('Done: ' + totalFixed + ' replacements in ' + filesFixed + ' files'\);
